#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    long long x = *(const long long *)a;
    long long y = *(const long long *)b;
    return (x > y) - (x < y);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *a = (long long*)malloc(N * sizeof(long long));
        long long total = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &a[i]);
            total ^= a[i];
        }
        if (total == 0) {
            printf("-1\n");
            free(a);
            continue;
        }
        qsort(a, N, sizeof(long long), cmp);
        long long pref = 0;
        for (int i = 0; i < N; ++i) {
            pref ^= a[i];
            if (pref == 0 && i + 1 < N) {
                long long tmp = a[i];
                a[i] = a[i+1];
                a[i+1] = tmp;
                pref ^= a[i]; // recompute prefix for current position after swap
                pref ^= tmp;   // remove old contribution
                pref ^= a[i]; // add new contribution (same as first line after swap)
                // simpler: recompute pref from scratch up to i
                pref = 0;
                for (int j = 0; j <= i; ++j) pref ^= a[j];
            }
        }
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%lld", a[i]);
        }
        printf("\n");
        free(a);
    }
    return 0;
}

