#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        total = 0
        for v in a:
            total ^= v
        if total == 0:
            out_lines.append('-1')
            continue
        a.sort()
        pref = 0
        i = 0
        while i < N:
            pref ^= a[i]
            if pref == 0 and i + 1 < N:
                a[i], a[i+1] = a[i+1], a[i]
                pref = 0
                for j in range(i+1):
                    pref ^= a[j]
            i += 1
        out_lines.append(' '.join(map(str, a)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

